import{_ as o,c as s,o as a,ao as r}from"./chunks/framework.DOhyS95j.js";const i="/handbook/assets/httpcache.Doel8ZcA.png",T=JSON.parse('{"title":"HTTP","description":"","frontmatter":{},"headers":[],"relativePath":"pages/http.md","filePath":"pages/http.md"}'),l={name:"pages/http.md"};function n(e,t,g,h,p,d){return a(),s("div",null,t[0]||(t[0]=[r(`<h1 id="http" tabindex="-1">HTTP <a class="header-anchor" href="#http" aria-label="Permalink to &quot;HTTP&quot;">​</a></h1><h2 id="http-协议特点" tabindex="-1">HTTP 协议特点 <a class="header-anchor" href="#http-协议特点" aria-label="Permalink to &quot;HTTP 协议特点&quot;">​</a></h2><p><strong>功能说明</strong>：HTTP 协议的核心特性，决定了其在 Web 通信中的行为。</p><ul><li><strong>简单快速</strong>：客户向服务器请求服务时，只需传送请求方法和路径。请求方法常用的有 <strong>GET</strong>、<strong>HEAD</strong>、<strong>POST</strong>。每种方法规定了客户与服务器联系的类型不同。由于 HTTP 协议简单，使得 HTTP 服务器的程序规模小，因而通信速度很快。</li><li><strong>灵活</strong>：HTTP 允许传输任意类型的数据对象。正在传输的类型由 <strong>Content-Type</strong> 加以标记。</li><li><strong>无连接</strong>：无连接的含义是限制每次连接只处理一个请求。服务器处理完客户的请求，并收到客户的应答后，即断开连接。采用这种方式可以节省传输时间。</li><li><strong>无状态</strong>：HTTP 协议是无状态协议。无状态是指协议对于事务处理没有记忆能力。缺少状态意味着如果后续处理需要前面的信息，则它必须重传，这样可能导致每次连接传送的数据量增大。另一方面，在服务器不需要先前信息时它的应答就较快。</li><li><strong>支持 B/S 及 C/S 模式</strong>：适用于浏览器-服务器和客户端-服务器架构。</li></ul><h2 id="http-报文的组成部分" tabindex="-1">HTTP 报文的组成部分 <a class="header-anchor" href="#http-报文的组成部分" aria-label="Permalink to &quot;HTTP 报文的组成部分&quot;">​</a></h2><p><strong>功能说明</strong>：HTTP 报文是 HTTP 协议中客户端与服务器之间传递数据的格式。</p><h3 id="请求报文组成" tabindex="-1">请求报文组成 <a class="header-anchor" href="#请求报文组成" aria-label="Permalink to &quot;请求报文组成&quot;">​</a></h3><ol><li><p><strong>请求行</strong>：用来说明请求类型、要访问的资源以及所使用的 HTTP 版本。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /hu.jpg HTTP/1.1</span></span></code></pre></div><blockquote><p><code>GET</code> 说明请求类型为 GET，<code>/hu.jpg</code> 为要访问的资源，该行的最后一部分说明使用的是 HTTP 1.1 版本。</p></blockquote></li><li><p><strong>请求头部</strong>：紧接着请求行之后的部分，用来说明服务器要使用的附加信息。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HOST: example.com</span></span>
<span class="line"><span>User-Agent: Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36</span></span></code></pre></div><blockquote><p><code>HOST</code> 将指出请求的目的地。<code>User-Agent</code> 是浏览器类型检测逻辑的重要基础，由浏览器定义并在每个请求中自动发送。</p></blockquote></li><li><p><strong>空行</strong>：请求头部后面的空行是必须的。</p><blockquote><p>即使第四部分的请求数据为空，也必须有空行。</p></blockquote></li><li><p><strong>请求数据</strong>：也叫主体，可以添加任意的其他数据。</p><blockquote><p>这个例子的请求数据为空。</p></blockquote></li></ol><h2 id="http-状态码" tabindex="-1">HTTP 状态码 <a class="header-anchor" href="#http-状态码" aria-label="Permalink to &quot;HTTP 状态码&quot;">​</a></h2><p><strong>功能说明</strong>：HTTP 状态码是服务器对客户端请求的响应状态的数字代码，用于表示请求的处理结果。</p><h3 id="状态码分类" tabindex="-1">状态码分类 <a class="header-anchor" href="#状态码分类" aria-label="Permalink to &quot;状态码分类&quot;">​</a></h3><ul><li><strong>1xx</strong>：指示信息 -- 表示请求已接收，继续处理</li><li><strong>2xx</strong>：成功 -- 表示请求已被成功接收、理解、接受</li><li><strong>3xx</strong>：重定向 -- 要完成请求必须进行更进一步的操作</li><li><strong>4xx</strong>：客户端错误 -- 请求有语法错误或请求无法实现</li><li><strong>5xx</strong>：服务器端错误 -- 服务器未能实现合法的请求</li></ul><h3 id="常见状态码" tabindex="-1">常见状态码 <a class="header-anchor" href="#常见状态码" aria-label="Permalink to &quot;常见状态码&quot;">​</a></h3><ul><li><strong>200 OK</strong>：客户端请求成功</li><li><strong>201 Created</strong>：已创建</li><li><strong>202 Accepted</strong>：已接受</li><li><strong>203 Non-Authoritative Information</strong>：非授权信息</li><li><strong>204 No Content</strong>：成功，无内容</li><li><strong>205 Reset Content</strong>：成功，重置内容</li><li><strong>206 Partial Content</strong>：成功，部分内容（断点续传）</li><li><strong>301 Moved Permanently</strong>：永久移动，重定向</li><li><strong>302 Found</strong>：临时移动，可使用原有 URI</li><li><strong>304 Not Modified</strong>：资源未修改，可使用缓存</li><li><strong>305 Use Proxy</strong>：需代理访问</li><li><strong>400 Bad Request</strong>：客户端请求有语法错误，不能被服务器所理解</li><li><strong>401 Unauthorized</strong>：请求未经授权，这个状态代码必须和 WWW-Authenticate 报头域一起使用</li><li><strong>403 Forbidden</strong>：服务器收到请求，但是拒绝提供服务</li><li><strong>404 Not Found</strong>：请求资源不存在，例如输入了错误的 URL</li><li><strong>500 Internal Server Error</strong>：服务器发生不可预期的错误</li><li><strong>503 Service Unavailable</strong>：服务器当前不能处理客户端的请求，一段时间后可能恢复正常</li></ul><h2 id="get、post-区别" tabindex="-1">GET、POST 区别 <a class="header-anchor" href="#get、post-区别" aria-label="Permalink to &quot;GET、POST 区别&quot;">​</a></h2><p><strong>功能说明</strong>：GET 和 POST 是 HTTP 协议中最常用的两种请求方法，它们在使用场景和行为上有明显区别。</p><ul><li><strong>缓存</strong>：GET 请求会被浏览器主动缓存，POST 不会，除非手动设置</li><li><strong>参数限制</strong>：GET 请求参数在 URL 中是会限制的，POST 没有限制</li><li><strong>参数位置</strong>：GET 请求参数在 URL 中，POST 放在 request body 中</li><li><strong>安全性</strong>：GET 请求参数暴露在 URL 中，POST 请求参数在请求体中，相对更安全</li><li><strong>幂等性</strong>：GET 请求是幂等的（多次请求结果相同），POST 请求是非幂等的（多次请求可能产生不同结果）</li></ul><h2 id="长连接与短连接" tabindex="-1">长连接与短连接 <a class="header-anchor" href="#长连接与短连接" aria-label="Permalink to &quot;长连接与短连接&quot;">​</a></h2><p><strong>功能说明</strong>：长连接和短连接是 HTTP 协议中两种不同的连接管理方式，影响着客户端与服务器之间的通信效率。</p><ul><li><p><strong>短连接</strong>：在 HTTP/1.0 中默认使用。客户端和服务器每进行一次 HTTP 操作，就建立一次连接，任务结束就中断连接。当客户端浏览器访问的某个 HTML 或其他类型的 Web 页中包含有其他的 Web 资源（如 JavaScript 文件、图像文件、CSS 文件等），每遇到这样一个 Web 资源，浏览器就会重新建立一个 HTTP 会话。</p></li><li><p><strong>长连接</strong>：从 HTTP/1.1 起，默认使用长连接，用以保持连接特性。使用长连接的 HTTP 协议，会在响应头加入这行代码：<code>Connection: keep-alive</code></p><blockquote><p>在使用长连接的情况下，当一个网页打开完成后，客户端和服务器之间用于传输 HTTP 数据的 TCP 连接不会关闭，客户端再次访问这个服务器时，会继续使用这一条已经建立的连接。Keep-Alive 不会永久保持连接，它有一个保持时间，可以在不同的服务器软件（如 Apache）中设定这个时间。实现长连接需要客户端和服务端都支持长连接。</p></blockquote></li><li><p><strong>本质</strong>：HTTP 协议的长连接和短连接，实质上是 TCP 协议的长连接和短连接。</p></li></ul><h2 id="http-缓存架构图" tabindex="-1">HTTP 缓存架构图 <a class="header-anchor" href="#http-缓存架构图" aria-label="Permalink to &quot;HTTP 缓存架构图&quot;">​</a></h2><p><img src="`+i+`" alt="httpcache"></p><h2 id="last-modified-etag" tabindex="-1">Last-Modified &amp; ETag <a class="header-anchor" href="#last-modified-etag" aria-label="Permalink to &quot;Last-Modified &amp; ETag&quot;">​</a></h2><p><strong>功能说明</strong>：Last-Modified 和 ETag 是 HTTP 协议中用于缓存验证的两种机制，用于判断资源是否发生变化。</p><h3 id="基本概念" tabindex="-1">基本概念 <a class="header-anchor" href="#基本概念" aria-label="Permalink to &quot;基本概念&quot;">​</a></h3><ul><li><strong>Last-Modified</strong>：文件最后修改的时间</li><li><strong>ETag</strong>：服务端对文件的索引节、大小和最后修改时间进行 Hash 后得到的值</li></ul><h3 id="为什么需要-etag" tabindex="-1">为什么需要 ETag？ <a class="header-anchor" href="#为什么需要-etag" aria-label="Permalink to &quot;为什么需要 ETag？&quot;">​</a></h3><ol><li><strong>时间精度问题</strong>：如果在一秒钟之内对一个文件进行两次更改，Last-Modified 可能就会不正确</li><li><strong>服务器限制</strong>：某些服务器不能精确的得到文件的最后修改时间</li><li><strong>内容未变</strong>：一些文件也许会周期性的更改，但是内容并不改变（仅仅改变的修改时间），这个时候我们并不希望客户端认为这个文件被修改了，而重新 GET</li></ol><h3 id="为什么需要-last-modified" tabindex="-1">为什么需要 Last-Modified？ <a class="header-anchor" href="#为什么需要-last-modified" aria-label="Permalink to &quot;为什么需要 Last-Modified？&quot;">​</a></h3><ul><li><strong>性能优化</strong>：对于一些图片等静态文件的修改，如果每次扫描内容生成 ETag 来比较，显然要比直接比较修改时间慢很多</li><li><strong>互补性</strong>：两种判断机制相辅相成，共同提高缓存验证的准确性</li></ul><h2 id="强缓存与协商缓存" tabindex="-1">强缓存与协商缓存 <a class="header-anchor" href="#强缓存与协商缓存" aria-label="Permalink to &quot;强缓存与协商缓存&quot;">​</a></h2><p><strong>功能说明</strong>：HTTP 缓存机制分为强缓存和协商缓存两种，用于减少网络请求，提高页面加载速度。</p><h3 id="强缓存" tabindex="-1">强缓存 <a class="header-anchor" href="#强缓存" aria-label="Permalink to &quot;强缓存&quot;">​</a></h3><p>强缓存时间未过期不会主动向服务器发请求，浏览器直接从本地缓存读取资源。</p><ul><li><strong>Cache-Control</strong>： <ul><li><strong>max-age</strong>：浏览器缓存时间，时间未过期直接读取浏览器缓存</li><li><strong>s-max-age</strong>：CDN 缓存时间，s-max-age 大于 max-age，优先读取 CDN</li><li><strong>private</strong>：私有的缓存一般存在浏览器</li><li><strong>public</strong>：公共的缓存一般存在 CDN 服务器</li><li><strong>no-store</strong>：禁用缓存</li></ul></li><li><strong>Expires</strong>：缓存过期时间，max-age 优先级高于 Expires</li></ul><h3 id="协商缓存" tabindex="-1">协商缓存 <a class="header-anchor" href="#协商缓存" aria-label="Permalink to &quot;协商缓存&quot;">​</a></h3><p>当强缓存过期后，浏览器会向服务器发送请求，验证资源是否发生变化。</p><ul><li><p><strong>Last-Modified / If-Modified-Since</strong>：</p><ul><li><strong>Last-Modified</strong>：服务器资源最后一次修改的时间，存在 response</li><li><strong>If-Modified-Since</strong>：浏览器请求时会带上 If-Modified-Since 时间，服务器对比时间相同返回 304 读取浏览器缓存，不同返回 200 重新请求资源</li></ul></li><li><p><strong>ETag / If-None-Match</strong>：</p><ul><li><strong>ETag</strong>：服务端生成的资源唯一标识，存在 response</li><li><strong>If-None-Match</strong>：浏览器请求时会带上 If-None-Match 值，服务器对比相同返回 304 读取浏览器缓存，不同返回 200 重新请求资源</li></ul></li></ul><h3 id="优先级" tabindex="-1">优先级 <a class="header-anchor" href="#优先级" aria-label="Permalink to &quot;优先级&quot;">​</a></h3><ul><li><strong>强缓存</strong> &gt; <strong>协商缓存</strong></li><li><strong>Cache-Control</strong> &gt; <strong>Expires</strong></li><li><strong>ETag</strong> &gt; <strong>Last-Modified</strong></li></ul><h2 id="刷新操作对缓存的影响" tabindex="-1">刷新操作对缓存的影响 <a class="header-anchor" href="#刷新操作对缓存的影响" aria-label="Permalink to &quot;刷新操作对缓存的影响&quot;">​</a></h2><p><strong>功能说明</strong>：不同的刷新操作会对浏览器缓存产生不同的影响，导致资源加载方式的变化。</p><ul><li><strong>正常操作</strong>：强制缓存有效，协商缓存有效</li><li><strong>手动刷新</strong>（浏览器上的刷新）：强制缓存失效，协商缓存有效</li><li><strong>强制刷新</strong>（Ctrl + F5）：强制缓存失效，协商缓存失效</li></ul><h2 id="http-2-0-的优势" tabindex="-1">HTTP 2.0 的优势 <a class="header-anchor" href="#http-2-0-的优势" aria-label="Permalink to &quot;HTTP 2.0 的优势&quot;">​</a></h2><p><strong>功能说明</strong>：HTTP 2.0 是 HTTP 协议的重大升级，带来了显著的性能提升和新特性。</p><ul><li><strong>二进制格式传输</strong>：采用<strong>二进制格式传输数据</strong>，而非 HTTP 1.1 的文本格式，二进制格式在协议的解析和优化扩展上带来更多的优势和可能</li><li><strong>头部压缩</strong>：对消息头采用<strong>HPACK 进行压缩传输</strong>，能够节省消息头占用的网络流量，而 HTTP 1.1 每次请求都会携带大量冗余头信息，浪费了很多带宽资源</li><li><strong>多路复用</strong>：多个请求通过一个 TCP 连接并发完成，HTTP 1.1 虽然通过 pipeline 也能并发请求，但是多个请求之间的响应会被阻塞，所以 pipeline 至今也没有被普及应用，而 HTTP 2.0 做到了真正的并发请求，同时，流还支持优先级和流量控制</li><li><strong>Server Push</strong>：服务端能够更快的把资源推送给客户端，例如服务端可以主动把 JS 和 CSS 文件推送给客户端，而不需要客户端解析 HTML 再发送这些请求，当客户端需要的时候，它已经在客户端了</li></ul><h2 id="同源策略" tabindex="-1">同源策略 <a class="header-anchor" href="#同源策略" aria-label="Permalink to &quot;同源策略&quot;">​</a></h2><p><strong>功能说明</strong>：同源策略是浏览器的一种安全机制，限制了来自不同源的文档或脚本对当前文档的访问能力。</p><ul><li><strong>同源的定义</strong>：<strong>协议相同</strong>、<strong>域名相同</strong>、<strong>端口相同</strong></li></ul><blockquote><p>例如：<code>https://example.com:8080</code> 和 <code>https://example.com:8080</code> 是同源，而 <code>http://example.com</code>、<code>https://www.example.com</code> 或 <code>https://example.com:8081</code> 都不是同源</p></blockquote><h2 id="跨域请求限制" tabindex="-1">跨域请求限制 <a class="header-anchor" href="#跨域请求限制" aria-label="Permalink to &quot;跨域请求限制&quot;">​</a></h2><p><strong>功能说明</strong>：由于同源策略的存在，浏览器对跨域请求施加了一系列限制，以保护用户安全。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>跨域是浏览器的限制，和服务端无关</p></div><ul><li><strong>Cookie、localStorage 等存储无法读取</strong></li><li><strong>DOM 无法操作</strong></li><li><strong>Ajax 不能发送</strong>：Ajax 只能在同源下使用</li></ul><h2 id="不受同源策略限制的情况" tabindex="-1">不受同源策略限制的情况 <a class="header-anchor" href="#不受同源策略限制的情况" aria-label="Permalink to &quot;不受同源策略限制的情况&quot;">​</a></h2><p><strong>功能说明</strong>：虽然浏览器有同源策略限制，但有一些技术和方法可以绕过这些限制，实现跨域通信。</p><ul><li><strong>WebSocket</strong>：不受同源策略的限制，可直接与不同源的服务器建立连接</li><li><strong>window.postMessage</strong>：HTML5 中新引进的方法，可用于跨域传送数据</li><li><strong>CORS</strong>：服务器设置 <code>Access-Control-Allow-Origin</code> 头部，允许跨域请求</li><li><strong>JSONP</strong>：利用 script 标签不受跨域限制的特性，让服务器端返回可执行的回调函数，从而获取数据</li></ul><h2 id="跨域请求" tabindex="-1">跨域请求 <a class="header-anchor" href="#跨域请求" aria-label="Permalink to &quot;跨域请求&quot;">​</a></h2><p><strong>功能说明</strong>：跨域请求是指从一个源向另一个源发送的 HTTP 请求，需要遵循浏览器的跨域策略。</p><ul><li><strong>预检机制</strong>：跨域如果是复杂请求会有一个<strong>OPTIONS 预检机制</strong>，预检通过成功后才会发送真正的请求</li><li><strong>简单请求</strong>：GET、POST 等基本请求方法，且头部信息不包含自定义字段</li><li><strong>复杂请求</strong>：除简单请求外的其他请求，或添加了自定义头部信息的请求</li><li><strong>Cookie 限制</strong>：默认情况下，cookie 不允许跨域传递</li></ul><h2 id="跨域预检请求优化" tabindex="-1">跨域预检请求优化 <a class="header-anchor" href="#跨域预检请求优化" aria-label="Permalink to &quot;跨域预检请求优化&quot;">​</a></h2><p><strong>功能说明</strong>：OPTIONS 预检请求可能会导致请求变慢，需要采取措施进行优化。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>OPTIONS（预检/嗅探请求）可能会导致请求变慢，每次进行接口请求时，浏览器会先发出一个 OPTIONS 请求，然后才发起正式的请求。</p></div><h3 id="优化方法" tabindex="-1">优化方法 <a class="header-anchor" href="#优化方法" aria-label="Permalink to &quot;优化方法&quot;">​</a></h3><p>通过设置响应头部的 <code>Access-Control-Max-Age</code> 来设置预检请求有效期，即在设置的时间内只有第一次会发送预检请求，下次相同接口的请求（相同接口 &amp; 相同参数）不会再发出预检请求，而是直接发送真实请求。</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">location</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> /api/ </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  add_header </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Access-Control-Max-Age&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 600</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  proxy_pass </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://a**********/;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><blockquote><p>这样可以有效减少 OPTIONS 请求的次数，提高跨域请求的性能</p></blockquote><h2 id="http-对比-https" tabindex="-1">HTTP 对比 HTTPS <a class="header-anchor" href="#http-对比-https" aria-label="Permalink to &quot;HTTP 对比 HTTPS&quot;">​</a></h2><ul><li><strong>HTTP</strong> 是明文传输，敏感信息容易被中间劫持</li><li><strong>HTTPS</strong> = HTTP + SSL/TLS 非对称加密，劫持了也无法解密</li></ul><h2 id="对称加密" tabindex="-1">对称加密 <a class="header-anchor" href="#对称加密" aria-label="Permalink to &quot;对称加密&quot;">​</a></h2><p><strong>功能说明</strong>：对称加密是一种加密方式，使用同一个密钥进行加密和解密。</p><ul><li><strong>原理</strong>：加解密都是用的同一个 <strong>key</strong></li><li><strong>特点</strong>：加密速度快，但密钥管理困难，需要安全的密钥传输渠道</li></ul><h2 id="非对称加密" tabindex="-1">非对称加密 <a class="header-anchor" href="#非对称加密" aria-label="Permalink to &quot;非对称加密&quot;">​</a></h2><p><strong>功能说明</strong>：非对称加密是一种加密方式，使用一对密钥（公钥和私钥）进行加密和解密。</p><ul><li><strong>密钥对</strong>：会生成一对 <strong>公钥 (Public Key)</strong> 和 <strong>私钥 (Private Key)</strong></li><li><strong>加密解密</strong>：用 <strong>公钥</strong> 进行加密，<strong>私钥</strong> 解密</li><li><strong>签名验证</strong>：用 <strong>私钥</strong> 签名，<strong>公钥</strong> 验证</li><li><strong>安全性</strong>：私钥不会对外公开，相对安全指数高</li></ul><h2 id="http-2-的多路复用" tabindex="-1">HTTP 2 的多路复用 <a class="header-anchor" href="#http-2-的多路复用" aria-label="Permalink to &quot;HTTP 2 的多路复用&quot;">​</a></h2><p><strong>功能说明</strong>：HTTP 2 的多路复用是一项重要的性能优化技术，解决了 HTTP 1.x 中的队头阻塞问题。</p><h3 id="http-1-x-的问题" tabindex="-1">HTTP 1.x 的问题 <a class="header-anchor" href="#http-1-x-的问题" aria-label="Permalink to &quot;HTTP 1.x 的问题&quot;">​</a></h3><p>在 HTTP/1 中，每次请求都会建立一次 HTTP 连接，也就是我们常说的 3 次握手 4 次挥手，这个过程在一次请求过程中占用了相当长的时间，即使开启了 Keep-Alive ，解决了多次连接的问题，但是依然有两个效率上的问题：</p><ol><li><p><strong>串行的文件传输</strong>：当请求 a 文件时，b 文件只能等待，等待 a 连接到服务器、服务器处理文件、服务器返回文件，这三个步骤。我们假设这三步用时都是 1 秒，那么 a 文件用时为 3 秒，b 文件传输完成用时为 6 秒，依此类推。（注：此项计算有一个前提条件，就是浏览器和服务器是单通道传输）</p></li><li><p><strong>连接数过多</strong>：我们假设 Apache 设置了最大并发数为 300，因为浏览器限制，浏览器发起的最大请求数为 6，也就是服务器能承载的最高并发为 50，当第 51 个人访问时，就需要等待前面某个请求处理完成。</p></li></ol><h3 id="http-2-的解决方案" tabindex="-1">HTTP 2 的解决方案 <a class="header-anchor" href="#http-2-的解决方案" aria-label="Permalink to &quot;HTTP 2 的解决方案&quot;">​</a></h3><p>HTTP/2 的多路复用就是为了解决上述的两个性能问题。在 HTTP/2 中，有两个非常重要的概念：</p><ul><li><strong>帧（frame）</strong>：代表着最小的数据单位，每个帧会标识出该帧属于哪个流</li><li><strong>流（stream）</strong>：多个帧组成的数据流</li></ul><p><strong>多路复用</strong>：在一个 TCP 连接中可以存在多条流。换句话说，也就是可以发送多个请求，对端可以通过帧中的标识知道属于哪个请求。通过这个技术，可以避免 HTTP 旧版本中的队头阻塞问题，极大的提高传输性能。</p><h2 id="https-中间人攻击" tabindex="-1">HTTPS 中间人攻击 <a class="header-anchor" href="#https-中间人攻击" aria-label="Permalink to &quot;HTTPS 中间人攻击&quot;">​</a></h2><p><strong>功能说明</strong>：中间人攻击是一种常见的网络攻击方式，攻击者在客户端和服务器之间拦截和篡改通信数据。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>服务端在发送浏览器的公钥中加入 CA 证书，浏览器可以验证 CA 证书的有效性，从而防止中间人攻击。</p></div><h3 id="攻击过程" tabindex="-1">攻击过程 <a class="header-anchor" href="#攻击过程" aria-label="Permalink to &quot;攻击过程&quot;">​</a></h3><ol><li><strong>服务器向客户端发送公钥</strong></li><li><strong>攻击者截获公钥</strong>，保留在自己手上</li><li><strong>攻击者生成伪造的公钥</strong>，发给客户端</li><li><strong>客户端收到伪造的公钥</strong>，生成加密 hash 值发给服务器</li><li><strong>攻击者获得加密 hash 值</strong>，用自己的私钥解密获得真密钥</li><li><strong>攻击者生成假的加密 hash 值</strong>，发给服务器</li><li><strong>服务器用私钥解密获得假密钥</strong></li><li><strong>服务器用假密钥加密传输信息</strong>，攻击者可以截获并解密</li></ol><h3 id="防护措施" tabindex="-1">防护措施 <a class="header-anchor" href="#防护措施" aria-label="Permalink to &quot;防护措施&quot;">​</a></h3><ul><li><strong>使用 CA 证书</strong>：服务端使用由可信 CA 签发的证书，浏览器会验证证书的有效性</li><li><strong>证书验证</strong>：客户端在收到证书后，会验证证书的签名和有效期</li><li><strong>HTTPS</strong>：使用 HTTPS 协议，确保通信加密</li></ul><h2 id="tcp-和-udp-区别" tabindex="-1">TCP 和 UDP 区别 <a class="header-anchor" href="#tcp-和-udp-区别" aria-label="Permalink to &quot;TCP 和 UDP 区别&quot;">​</a></h2><p><strong>功能说明</strong>：TCP 和 UDP 是两种不同的传输层协议，它们在连接方式、可靠性、传输效率等方面有显著区别。</p><ul><li><strong>连接方式</strong>：TCP 面向连接（如打电话要先拨号建立连接），UDP 是无连接的，即发送数据之前不需要建立连接</li><li><strong>可靠性</strong>：TCP 提供可靠的服务，UDP 尽最大努力交付，即不保证可靠交付</li><li><strong>实时性</strong>：UDP 具有较好的实时性，工作效率比 TCP 高，适用于对高速传输和实时性有较高的通信或广播通信</li><li><strong>连接数</strong>：每一条 TCP 连接只能是一对一的，UDP 支持一对一，一对多，多对一和多对多的交互通信</li><li><strong>首部开销</strong>：UDP 分组首部开销小（只有 8 个字节），TCP 首部开销较大（20 字节）</li><li><strong>数据传输</strong>：TCP 面向字节流，实际上是 TCP 把数据看成一连串无结构的字节流；UDP 是面向报文的，一次交付一个完整的报文，报文不可分割，报文是 UDP 数据报处理的最小单位</li><li><strong>应用场景</strong>：UDP 适合一次性传输较小数据的网络应用，如 DNS，SNMP 等；TCP 适合需要可靠传输的应用，如 HTTP，FTP 等</li></ul><h2 id="为什么有非对称加密-还需要-ca-证书" tabindex="-1">为什么有非对称加密，还需要 CA 证书？ <a class="header-anchor" href="#为什么有非对称加密-还需要-ca-证书" aria-label="Permalink to &quot;为什么有非对称加密，还需要 CA 证书？&quot;">​</a></h2><p><strong>功能说明</strong>：非对称加密虽然安全，但存在密钥验证的问题，CA 证书可以解决这个问题。</p><ul><li><strong>非对称加密的问题</strong>：无法证明公开密钥就是接收方公开的那个密钥，而不是被攻击者调包的密钥</li><li><strong>CA 证书的作用</strong>：由数字证书认证机构（CA，Certificate Authority）颁发的<strong>公开密钥证书</strong>，用于验证公钥的真实性</li><li><strong>CA 的角色</strong>：数字证书认证机构处于客户端与服务器双方都可信赖的第三方机构的立场上，相当于公证处，大家都相信公证处，你说你是张三别人不一定信，它说你是张三别人才能百分百信</li></ul><h2 id="tcp-连接-三次握手与四次挥手" tabindex="-1">TCP 连接：三次握手与四次挥手 <a class="header-anchor" href="#tcp-连接-三次握手与四次挥手" aria-label="Permalink to &quot;TCP 连接：三次握手与四次挥手&quot;">​</a></h2><p><strong>功能说明</strong>：TCP 连接的建立和关闭过程，分别通过三次握手和四次挥手来完成。</p><h3 id="三次握手" tabindex="-1">三次握手 <a class="header-anchor" href="#三次握手" aria-label="Permalink to &quot;三次握手&quot;">​</a></h3><p><strong>功能说明</strong>：三次握手是 TCP 建立连接的过程，确保客户端和服务器之间的通信链路正常。</p><p><strong>过程</strong>：</p><ol><li><strong>客户端发送 SYN 包</strong>，服务端收到。服务端确认：客户端的发送能力是正常的</li><li><strong>服务端发送 SYN+ACK 包</strong>，客户端收到。客户端确认：服务端的接收和发送能力是正常的</li><li><strong>客户端发送 ACK 包</strong>，服务端收到。服务端确认：客户端的接收能力是正常的，连接建立完成</li></ol><p>建立连接完成，然后就开始发送数据，通讯。</p><h3 id="四次挥手" tabindex="-1">四次挥手 <a class="header-anchor" href="#四次挥手" aria-label="Permalink to &quot;四次挥手&quot;">​</a></h3><p><strong>功能说明</strong>：四次挥手是 TCP 关闭连接的过程，确保双方都已完成数据传输。</p><p><strong>过程</strong>：</p><ol><li><strong>客户端发送 FIN 包</strong>，服务端接收。服务端确认：客户端已经请求结束</li><li><strong>服务端发送 ACK 包</strong>，客户端接收。客户端确认：服务端已经收到关闭请求，等待服务端关闭</li><li><strong>服务端发送 FIN 包</strong>，客户端接收。客户端确认：服务端已经发送完成，可以关闭</li><li><strong>客户端发送 ACK 包</strong>，服务端接收。服务端确认：可以关闭了</li></ol>`,108)]))}const u=o(l,[["render",n]]);export{T as __pageData,u as default};
